-- Migration 024 — RLS policies para companies e users-- Idempotente: DROP POLICY IF EXISTS + CREATE POLICY-- Depende de: app.current_company_id (setado via requireCompany middleware)-- Contexto: app_runtime role (NOBYPASSRLS) verá apenas a própria empresa-- Master admin acessa via pool principal (postgres, BYPASSRLS)-- Sem dependência de app.auth_scope — apenas app.current_company_id-- companies: policies específicas por operaçãoALTER TABLE IF EXISTS companies ENABLE ROW LEVEL SECURITY;DROP POLICY IF EXISTS companies_select_own ON companies;CREATE POLICY companies_select_own ON companies FOR SELECT  USING (id = NULLIF(current_setting('app.current_company_id', true), '')::uuid);DROP POLICY IF EXISTS companies_update_own ON companies;CREATE POLICY companies_update_own ON companies FOR UPDATE  USING (id = NULLIF(current_setting('app.current_company_id', true), '')::uuid)  WITH CHECK (id = NULLIF(current_setting('app.current_company_id', true), '')::uuid);-- INSERT companies: sem policy → default DENY (app_runtime não cria empresas)-- DELETE companies: sem policy → default DENY (app_runtime não deleta empresas)-- users: policies específicas por operaçãoALTER TABLE IF EXISTS users ENABLE ROW LEVEL SECURITY;DROP POLICY IF EXISTS users_select_own_company ON users;CREATE POLICY users_select_own_company ON users FOR SELECT  USING (company_id = NULLIF(current_setting('app.current_company_id', true), '')::uuid);DROP POLICY IF EXISTS users_insert_own_company ON users;CREATE POLICY users_insert_own_company ON users FOR INSERT  WITH CHECK (company_id = NULLIF(current_setting('app.current_company_id', true), '')::uuid);DROP POLICY IF EXISTS users_update_own_company ON users;CREATE POLICY users_update_own_company ON users FOR UPDATE  USING (company_id = NULLIF(current_setting('app.current_company_id', true), '')::uuid)  WITH CHECK (company_id = NULLIF(current_setting('app.current_company_id', true), '')::uuid);-- DELETE users: sem policy → default DENY (soft-delete via is_deleted)